const { sql } = require('slonik');

function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === 'string') {
    return tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  if (Array.isArray(tags)) {
    return tags.map(t => t.toLowerCase()).filter(t => t.length > 0);
  }
  return [];
}

async function solve({ difficulty, limit, tags }, db) {
  const normalizedTags = normalizeTags(tags);

  const conditions = [];
  const params = {};

  if (difficulty) {
    conditions.push(sql`difficulty = ${difficulty}`);
  }

  if (normalizedTags.length > 0) {
    // Filter problems that have at least one tag in normalizedTags
    conditions.push(sql`EXISTS (
      SELECT 1 FROM problem_tags pt
      WHERE pt.problem_id = problems.id
      AND LOWER(pt.tag) = ANY(${normalizedTags})
    )`);
  }

  const whereClause = conditions.length > 0 ? sql`WHERE ${sql.join(conditions, sql` AND `)}` : sql``;

  const query = sql`
    SELECT problems.*, 
      json_build_object('appliedTags', ${normalizedTags}) AS metadata
    FROM problems
    ${whereClause}
    ORDER BY problems.difficulty ASC, problems.id ASC
    LIMIT ${limit || 50}
  `;

  const result = await db.any(query);
  return result;
}

module.exports = { solve };
